// Source tenant: baseline host count
fetch dt.entity.host
| summarize host_count = count()
| fieldsAdd entity_type = "Hosts"

// Alternative: Smartscape on Grail (entity.name → name)
// smartscapeNodes HOST
// | summarize host_count = count()
